package kr.gampa.battlegrounds.vehicle; public record VehicleSpec(String id,VehicleType type,double topSpeedKmh,double reverseSpeedKmh,double turnRateDeg,int seats,double durability,double fuelCapacity,double acceleration,double fuelPerSecond,boolean armored){public VehicleSpec{if(id==null||topSpeedKmh<=0||seats<1||durability<=0||fuelCapacity<0)throw new IllegalArgumentException();}}